                      {plan.secondaryFee ? (
                        <p className="mt-4 text-lg font-medium leading-relaxed text-zinc-700">{plan.secondaryFee}</p>
                      ) : null}
                      <p className="mt-6 text-base leading-relaxed text-zinc-500">{plan.lead}</p>
                    </div>
                  </div>
                </section>
              );
            })}
